**Файл:** `internal/entity/order_test.go`

```go
package entity

import (
	"math"
	"testing"
)

// OrderItem – упрощённый тип, который используется в тестах.
// В реальном коде он объявлен в internal/entity/order.go, но для
// тестов нам достаточно знать только три поля.
type OrderItem struct {
	ProductID int64
	Quantity  int64   // количество единиц товара
	UnitPrice float64 // цена за одну единицу
}

// TestUnitOrderCalculateTotalEdgeCases проверяет метод
// Order.CalculateTotal() на «крайних» сценариях, которые ещё
// не покрыты существующими тестами (empty, single, typical,
// large‑order).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type testCase struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantErr     bool // если CalculateTotal() возвращает ошибку (не в текущей реализации,
		// но оставляем возможность расширения)
		precision   float64 // допустимая погрешность сравнения (для float‑проверок)
		description string // пояснение, почему выбран именно такой набор данных
	}

	cases := []testCase{
		{
			name: "zero_quantity",
			// Товар присутствует, но количество равно 0 → не должно влиять на сумму.
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, UnitPrice: 199.99},
				{ProductID: 2, Quantity: 3, UnitPrice: 49.50},
			},
			wantTotal:   3 * 49.50,
			precision:   0.0001,
			description: "Только товары с Quantity>0 учитываются в расчёте.",
		},
		{
			name: "negative_quantity",
			// Отрицательное количество – бизнес‑логика обычно считает такой заказ
			// некорректным. Мы проверяем, что метод игнорирует такие позиции
			// (т.к. в реальном коде валидация делается в Order.Validate()).
			items: []OrderItem{
				{ProductID: 1, Quantity: -2, UnitPrice: 100},
				{ProductID: 2, Quantity: 5, UnitPrice: 20},
			},
			wantTotal:   5 * 20,
			precision:   0.0001,
			description: "Отрицательные количества не учитываются в сумме.",
		},
		{
			name: "zero_price",
			// Товар с нулевой ценой – должен добавить 0 к общей сумме.
			items: []OrderItem{
				{ProductID: 1, Quantity: 4, UnitPrice: 0},
				{ProductID: 2, Quantity: 2, UnitPrice: 15.75},
			},
			wantTotal:   2 * 15.75,
			precision:   0.0001,
			description: "Товары с UnitPrice==0 не влияют на итоговую стоимость.",
		},
		{
			name: "large_quantity",
			// Проверяем, что при очень большом количестве не происходит переполнения
			// int64 → float64 (в Go float64 способен хранить до ~9e15 без потери точности).
			items: []OrderItem{
				{ProductID: 1, Quantity: 1_000_000, UnitPrice: 0.99},
			},
			wantTotal:   1_000_000 * 0.99,
			precision:   0.01, // небольшая погрешность из‑за представления в float64
			description: "Большие количества должны корректно суммироваться.",
		},
		{
			name: "floating_point_precision",
			// Тест на типичную проблему с плавающей точкой: 0.1*3 != 0.3 точно.
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, UnitPrice: 0.1},
			},
			wantTotal:   0.3,
			precision:   1e-9,
			description: "Проверка, что метод не теряет точность при обычных FP‑операциях.",
		},
		{
			name: "mixed_edge_cases",
			// Сочетание всех «крайних» вариантов в одном заказе.
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, UnitPrice: 123.45},   // zero qty
				{ProductID: 2, Quantity: -5, UnitPrice: 10},     // negative qty
				{ProductID: 3, Quantity: 2, UnitPrice: 0},       // zero price
				{ProductID: 4, Quantity: 1_000_000, UnitPrice: 1}, // large qty
				{ProductID: 5, Quantity: 3, UnitPrice: 0.1},     // fp precision
			},
			wantTotal:   1_000_000*1 + 3*0.1, // 1 000 000 + 0.3
			precision:   0.01,
			description: "Комбинация всех edge‑case‑ов в одном заказе.",
		},
	}

	for _, tc := range cases {
		tc := tc // захватываем переменную для параллельного запуска
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()

			// Формируем Order, используя те же структуры, что и в продакшн‑коде.
			o := &Order{
				Items: make([]OrderItem, len(tc.items)),
			}
			copy(o.Items, tc.items)

			// В реальном коде CalculateTotal() возвращает только float64,
			// но если в дальнейшем будет добавлена ошибка – покрываем её.
			got := o.CalculateTotal()

			// Сравниваем с учётом допускаемой погрешности.
			if diff := math.Abs(got - tc.wantTotal); diff > tc.precision {
				t.Fatalf("unexpected total: got %.10f, want %.10f (diff %.10f > %.10f) – %s",
					got, tc.wantTotal, diff, tc.precision, tc.description)
			}
		})
	}
}
```

### Что делает тест

| Сценарий                     | Что проверяется                                                                      |
|------------------------------|--------------------------------------------------------------------------------------|
| **zero_quantity**            | Товар с `Quantity == 0` не влияет на итоговую сумму.                                 |
| **negative_quantity**        | Отрицательные количества игнорируются (валидация делается в `Order.Validate`).      |
| **zero_price**               | Товар с нулевой ценой добавляет `0` к общей стоимости.                              |
| **large_quantity**           | Корректность расчёта при очень больших количествах (нет переполнения).               |
| **floating_point_precision**| Точность при типичных FP‑операциях (`0.1 * 3`).                                      |
| **mixed_edge_cases**         | Комбинация всех вышеописанных «крайних» вариантов в одном заказе.                    |

### Почему тест не дублирует существующие

| Существующий тест                     | Что покрывает                                                                 |
|--------------------------------------|-------------------------------------------------------------------------------|
| `TestUnitOrderCalculateTotal`        | «Обычный» заказ со средним количеством товаров.                               |
| `TestUnitOrderCalculateTotalEmpty`   | Пустой список товаров.                                                         |
| `TestUnitOrderCalculateTotalSingleItem`

